import type Collection from "../../core/Collection.js";
import type DisplayFilter from "./DisplayFilter.js";
import type { ClonableMixin } from "../../core/Clonable.js";
import type { JSONSupport } from "../../core/JSONSupport.js";
import type { DisplayFilterProperties } from "./DisplayFilter.js";
import type { ReadonlyArrayOrCollection } from "../../core/Collection.js";

export interface DisplayFilterInfoProperties extends Partial<Pick<DisplayFilterInfo, "activeFilterId" | "mode">> {
  /** A collection of [filters](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilter/) that define which features should be rendered on the display. */
  filters?: ReadonlyArrayOrCollection<DisplayFilterProperties>;
}

/**
 * Display filters are associated with a given layer and control which features are visible on the map. They allow you to display a subset of features while retaining access to all features
 * for querying and analysis. Unlike [FeatureLayer.definitionExpression](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#definitionExpression), which filters data at the source level, display filters only affect
 * visibility on the map. Therefore display filters should be ignored when querying data to present to users.
 *
 * Display filters are useful, for example, in a map of rivers across the United States, where you might want to show different types of rivers based on the zoom level.
 * A scale-dependent display filter could be applied to show only major rivers (like the Mississippi or Missouri) when zoomed out, giving a broad overview of the river network in the country. As the user zooms in,
 * the filter could automatically start displaying smaller rivers or tributaries that are otherwise too detailed to show at smaller scales.
 * In agricultural field mapping, a manual display filter could be applied to display the fields based on specific parameters, such as pest control, crop health, or irrigation, regardless of zoom level.
 * The user can toggle between these display filters, allowing them to focus on the most relevant information for their needs.
 *
 * A layer can contain multiple display filters, but only one filter can be applied at a time. The [mode](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilterInfo/#mode) defines the type of display filters that are associated with a layer.
 *
 * > [!WARNING]
 * >
 * > To optimize memory usage for rendering, display filters may be appended to the layer's [definitionExpression](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#definitionExpression) when querying the service.
 * > As a result, the filtered features may not be available on the client for executing layer view [queries](https://developers.arcgis.com/javascript/latest/references/core/views/layers/FeatureLayerView/#queryFeatures).
 * > To determine if all features are available in the view, check the layer view's [hasAllFeaturesInView](https://developers.arcgis.com/javascript/latest/references/core/views/layers/FeatureLayerView/#hasAllFeaturesInView)
 * > property when layer view's [dataUpdating](https://developers.arcgis.com/javascript/latest/references/core/views/layers/FeatureLayerView/#dataUpdating) is `false`. If `false`, the layer view does not have all features in the view
 * > and you should query the layer instead.
 *
 * @since 4.32
 * @see [DisplayFilter](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilter/)
 * @see [FeatureLayer.displayFilterInfo](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#displayFilterInfo)
 * @see [FeatureLayer.displayFilterEnabled](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#displayFilterEnabled)
 * @see [View.displayFilterEnabled](https://developers.arcgis.com/javascript/latest/references/core/views/View/#displayFilterEnabled)
 * @see [Sample - Scale-dependent DisplayFilter](https://developers.arcgis.com/javascript/latest/sample-code/display-filter/)
 */
export default class DisplayFilterInfo extends DisplayFilterInfoSuperclass {
  constructor(properties?: DisplayFilterInfoProperties);
  /** The active filter id. This filter is currently applied to the layer. The active filter is set when the display filter [mode](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilterInfo/#mode) is `manual`. */
  accessor activeFilterId: string | null | undefined;
  /** A collection of [filters](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilter/) that define which features should be rendered on the display. */
  get filters(): Collection<DisplayFilter>;
  set filters(value: ReadonlyArrayOrCollection<DisplayFilterProperties>);
  /**
   * The display filter mode. There are two modes to specify the active display filter:
   * * **Scale-dependent filter:** Each display filter on a layer is associated with a visible scale range. The active display filter is determined by the current scale of the view.
   * This approach is useful for layers with dense features at small scales where rendering can become difficult to interpret or slow.
   * When setting scale ranges, note that scale boundaries are treated as follows:
   *   * The [minScale](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilter/#minScale) is inclusive, meaning the filter is applied at this scale and all larger scales (i.e., when zoomed in).
   * The [maxScale](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilter/#maxScale) is exclusive, meaning the filter is applied up to (but not including) this scale.
   *   * Scale range filters can overlap or have gaps:
   *     * If filters overlap, the first filter in the [filters](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilterInfo/#filters) is applied.
   *     * If there are scale gaps between filters, no filter is applied.
   *
   * * **Manual filter:** Each display filter is defined by a [where](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilter/#where) clause and does not rely on scale. Only one filter can be active
   * at a time, and it must be manually selected by setting the [activeFilterId](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilterInfo/#activeFilterId) property to the [id](https://developers.arcgis.com/javascript/latest/references/core/layers/support/DisplayFilter/#id) property of the filter.
   * This filter mode is useful for making visual comparisons between different subsets of data.
   *
   * @default "manual"
   * @example
   * // loop through the layer's display filters and create a dropdown to select the active filter
   * layer.displayFilterInfo.filters.forEach((filter) => {
   *   const option = document.createElement("calcite-option");
   *   option.value = filter.id;
   *   option.innerText = filter.title;
   *   filterSelect.appendChild(option);
   * });
   *
   * // set the active filter when the user selects a filter from the dropdown
   * filterSelect.addEventListener("calciteSelectChange", () => {
   *   layer.displayFilterInfo.activeFilterId = filterSelect.value;
   * });
   */
  accessor mode: "manual" | "scale";
}
declare const DisplayFilterInfoSuperclass: typeof JSONSupport & typeof ClonableMixin